class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.setup_board()

    def setup_board(self):
        # Initialize pieces on the board
        for i in range(3):
            for j in (1, 3, 5, 7):
                self.board[i][j] = Piece('B')
        for i in range(5, 8):
            for j in (0, 2, 4, 6):
                self.board[i][j] = Piece('W')

    def print_board(self):
        for row in self.board:
            print(" ".join(str(piece) if piece else 'E' for piece in row))
